import { Result, ok, err } from '../types/result.ts';

export async function send_webhook(url: string, payload: OrderEvent): Promise<Result<void, WebhookError>> {
  const response = await fetch(url, { method: 'POST', body: JSON.stringify(payload) });
  if (!response.ok) return err(new WebhookError(response.status));
  return ok(undefined);
}

import { assertEquals } from 'testing/asserts';
import { send_webhook } from '../webhook.ts';

Deno.test('send_webhook returns ok on success', async () => {
  const result = await send_webhook('http://test', { orderId: '1', status: 'shipped' });
  assertEquals(result.ok, true);
});
